    {
      "content": "class EmbeddingEngine:\n    \"\"\"\n    Vector embedding engine using sentence-transformers.\n\n    Uses all-MiniLM-L6-v2: 22M params, 384 dims, ~15ms/1K tokens.\n    Loads model lazily on first use.\n    \"\"\"\n\n    _instance = None\n    _model = None\n\n    def __new__(cls):\n        \"\"\"Singleton pattern - only load model once.\"\"\"\n        if cls._instance is None:\n            cls._instance = super().__new__(cls)\n        return cls._instance\n\n    def _load_model(self):\n        \"\"\"Lazy load the embedding model.\"\"\"\n        if self._model is None:\n            try:\n                from sentence_transformers import SentenceTransformer\n                logger.info(\"Loading embedding model: all-MiniLM-L6-v2...\")\n                self._model = SentenceTransformer('all-MiniLM-L6-v2')\n                logger.info(\"Embedding model loaded.\")\n            except ImportError:\n                logger.warning(\"sentence-transformers not installed. Embeddings disabled.\")\n                logger.warning(\"Install with: pip install sentence-transformers\")\n                self._model = None\n            except Exception as e:\n                logger.error(f\"Failed to load embedding model: {e}\")\n                self._model = None\n\n    def embed(self, texts: List[str]) -> List[List[float]]:\n        \"\"\"\n        Generate embeddings for a list of texts.\n\n        Args:\n            texts: List of text strings to embed\n\n        Returns:\n            List of embedding vectors (384-dim each), or empty lists if unavailable\n        \"\"\"\n        self._load_model()\n\n        if self._model is None:\n            return [[] for _ in texts]\n\n        try:\n            embeddings = self._model.encode(texts, show_progress_bar=False)\n            return [emb.tolist() for emb in embeddings]\n        except Exception as e:\n            logger.error(f\"Embedding failed: {e}\")\n            return [[] for _ in texts]\n\n    def embed_single(self, text: str) -> List[float]:\n        \"\"\"Embed a single text string.\"\"\"\n        result = self.embed([text])\n        return result[0] if result else []\n\n    @property\n    def is_available(self) -> bool:\n        \"\"\"Check if embedding model is available.\"\"\"\n        self._load_model()\n        return self._model is not None\n\n    @property\n    def dimension(self) -> int:\n        \"\"\"Embedding dimension (384 for MiniLM).\"\"\"\n        return 384\n\n",
      "source_file": "/Users/lech/PROJECTS_all/PROJECT_elements/context-management/tools/ai/aci/refinery.py",
