    chunk_id: str                   # Unique ID (SHA256-based)
    chunk_type: str                 # Type: function, class, section, config_block, etc.
    relevance_score: float = 0.0    # 0.0-1.0 relevance score
    start_line: int = 0             # Line number in source (if applicable)
    end_line: int = 0               # End line number
    metadata: Dict[str, Any] = field(default_factory=dict)  # Additional metadata
    created_at: float = field(default_factory=time.time)
    embedding: List[float] = field(default_factory=list)  # Vector embedding (384-dim for MiniLM)

    # Fundamental Logistics ("The Mail")
    waybill: Dict[str, Any] = field(default_factory=dict) # Tracking info {parcel_id, parent_id, route}

    def to_dict(self) -> Dict[str, Any]:
        """Convert to JSON-serializable dict."""
        return asdict(self)

    @property
    def token_estimate(self) -> int:
        """Rough token count estimate (chars / 4)."""
        return len(self.content) // 4

    def __repr__(self) -> str:
        return f"RefineryNode({self.chunk_type}:{self.chunk_id[:8]}... {self.token_estimate}tok)"

class FileChunker(ABC):
    """Base class for file-specific chunking strategies."""

    def __init__(self, file_path: str):
        self.file_path = file_path
        self.content = ""
        self._load()

    def _load(self):
        """Load file content."""
        try:
            with open(self.file_path, 'r', encoding='utf-8', errors='replace') as f:
                self.content = f.read()
        except Exception as e:
            logger.error(f"Failed to load {self.file_path}: {e}")
            self.content = ""

    @abstractmethod
    def chunk(self) -> List[Tuple[str, str, int, int]]:
        """
        Split file into semantic chunks.

        Returns:
            List of (content, chunk_type, start_line, end_line) tuples
        """
        pass

class GenericChunker(FileChunker):
    """Generic chunker for unknown file types - splits by blank lines."""

    def chunk(self) -> List[Tuple[str, str, int, int]]:
        """Split by paragraph (double newlines)."""
        chunks = []

        paragraphs = re.split(r'\n\s*\n', self.content)
        line_num = 1

        for para in paragraphs:
            if para.strip():
                para_lines = para.count('\n') + 1
                chunks.append((para, 'paragraph', line_num, line_num + para_lines - 1))
                line_num += para_lines + 1  # +1 for blank line
            else:
                line_num += 1

        return chunks

def get_repo_id(repo_path: Path) -> Dict:
    """Get repository identification info."""
    try:
        commit = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True, text=True, cwd=repo_path
        ).stdout.strip()[:12]

        branch = subprocess.run(
            ["git", "rev-parse", "--abbrev-ref", "HEAD"],
            capture_output=True, text=True, cwd=repo_path
        ).stdout.strip()

        return {
            "commit": commit,
            "branch": branch,
            "timestamp": datetime.now().isoformat(),
            "version": REPOPACK_VERSION
        }
    except Exception:
        return {"commit": "unknown", "branch": "unknown", "timestamp": datetime.now().isoformat(), "version": REPOPACK_VERSION}

def get_file_tree(repo_path: Path, max_depth: int = 3, max_files: int = 200) -> str:
    """Get directory structure as tree string."""
    lines = []
    count = 0

    def walk(path: Path, prefix: str = "", depth: int = 0):
        nonlocal count
        if depth > max_depth or count > max_files:
            return

        try:
            entries = sorted(path.iterdir(), key=lambda x: (not x.is_dir(), x.name))
        except PermissionError:
            return

        dirs = [e for e in entries if e.is_dir() and not e.name.startswith('.')]
        files = [e for e in entries if e.is_file() and not e.name.startswith('.')]

        for d in dirs[:20]:  # Limit dirs per level
            lines.append(f"{prefix}{d.name}/")
            walk(d, prefix + "  ", depth + 1)

        for f in files[:30]:  # Limit files per level
            count += 1
            if count <= max_files:
                lines.append(f"{prefix}{f.name}")

    walk(repo_path)
    return "\n".join(lines[:max_files])

def get_hot_files(repo_path: Path, limit: int = 10) -> List[Dict]:
    """Get recently modified files with content."""
    try:
        result = subprocess.run(
            ["git", "diff", "--name-only", "HEAD~5", "HEAD"],
            capture_output=True, text=True, cwd=repo_path
        )
        files = result.stdout.strip().split("\n")[:limit]

        hot = []
        for f in files:
            if not f:
                continue
            path = repo_path / f
            if path.exists() and path.stat().st_size < 50000:  # Max 50KB
                try:
                    content = path.read_text(errors='ignore')[:10000]  # Max 10K chars
                    hot.append({"path": f, "content": content})
                except Exception:
                    pass
        return hot
    except Exception:
        return []

def get_cache_key(repo_path: Path) -> str:
    """Generate deterministic cache key for repo state."""
    repo_id = get_repo_id(Path(repo_path))

    # Check for uncommitted changes
    try:
        result = subprocess.run(
            ["git", "status", "--porcelain"],
            capture_output=True, text=True, cwd=repo_path
        )
        is_dirty = bool(result.stdout.strip())
    except Exception:
        is_dirty = True

    return f"{repo_id['commit']}_{'dirty' if is_dirty else 'clean'}"

